import React from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';
import { Ionicons } from '@expo/vector-icons';

const TABS = [
  { name: 'Home',          label: 'Home',    icon: 'home',                  iconOut: 'home-outline' },
  { name: 'Opportunities', label: 'Explore', icon: 'compass',               iconOut: 'compass-outline' },
  { name: 'Transactions',  label: 'Spend',   icon: 'card',                  iconOut: 'card-outline' },
  { name: 'Chat',          label: 'Ask AI',  icon: 'chatbubble-ellipses',   iconOut: 'chatbubble-ellipses-outline' },
  { name: 'Profile',       label: 'Profile', icon: 'person',                iconOut: 'person-outline' },
];

export default function WebTopNav({ state, navigation }) {
  return (
    <View style={styles.bar}>
      <View style={styles.inner}>
        <Text style={styles.logo}>Cerebral</Text>
        <View style={styles.tabs}>
          {TABS.map((tab, index) => {
            const active = state.index === index;
            return (
              <TouchableOpacity
                key={tab.name}
                onPress={() => navigation.navigate(tab.name)}
                style={[styles.tab, active && styles.tabActive]}
                activeOpacity={0.7}
              >
                <Ionicons
                  name={active ? tab.icon : tab.iconOut}
                  size={15}
                  color={active ? '#1a1a2e' : '#888'}
                />
                <Text style={[styles.label, active && styles.labelActive]}>
                  {tab.label}
                </Text>
              </TouchableOpacity>
            );
          })}
        </View>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  bar: {
    backgroundColor: '#fff',
    borderBottomWidth: 1,
    borderBottomColor: '#e8eaed',
  },
  inner: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    maxWidth: 960,
    alignSelf: 'center',
    width: '100%',
    paddingHorizontal: 28,
    height: 58,
  },
  logo: {
    fontSize: 19,
    fontWeight: '800',
    color: '#1a1a2e',
    letterSpacing: -0.5,
  },
  tabs: {
    flexDirection: 'row',
    gap: 2,
  },
  tab: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 6,
    paddingHorizontal: 13,
    paddingVertical: 7,
    borderRadius: 8,
  },
  tabActive: {
    backgroundColor: '#f0f2f5',
  },
  label: {
    fontSize: 13,
    fontWeight: '600',
    color: '#888',
  },
  labelActive: {
    color: '#1a1a2e',
  },
});
